const data = $json;
let response = '';
try {
  if (data.content && data.content.length > 0) {
    response = data.content.map(c => c.text || '').join('\n');
  } else if (data.error) {
    response = 'API Error: ' + (data.error.message || JSON.stringify(data.error));
  } else {
    response = JSON.stringify(data);
  }
} catch(e) {
  response = 'Parse error: ' + e.message;
}

const ctx = $('Build Context').first().json;
return [{ json: { response, session_id: ctx.session_id, mode: ctx.mode } }];
